class Solution:
    def minimizeStringValue(self, s: str) -> str:
        from collections import Counter

        # Convert string to list for easy modification
        s_list = list(s)
        freq = Counter()

        # First pass: count frequencies of existing characters
        for ch in s:
            if ch != '?':
                freq[ch] += 1

        # Second pass: replace '?' with the character that minimizes the cost
        for i in range(len(s_list)):
            if s_list[i] == '?':
                # Find the character with the smallest frequency
                # In case of tie, choose the lexicographically smallest
                min_char = None
                min_freq = float('inf')
                for ch in 'abcdefghijklmnopqrstuvwxyz':
                    if freq[ch] < min_freq:
                        min_freq = freq[ch]
                        min_char = ch
                # Replace '?' with the chosen character
                s_list[i] = min_char
                # Update frequency counter
                freq[min_char] += 1

        return ''.join(s_list)
